/**
 * StrategyCard — Compact strategy card component for list display.
 *
 * Features:
 * - Priority badge (P0 red / P1 amber / P2 blue)
 * - Status chip (active / draft)
 * - Title, subtitle
 * - Comment evidence preview (first 3)
 * - KPI tags
 * - Platform icon (📕/🎵)
 */
import React, { useState } from 'react';
import {
  Card,
  CardContent,
  CardActionArea,
  Typography,
  Chip,
  Box,
  Collapse,
  IconButton,
} from '@mui/material';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import ExpandLessIcon from '@mui/icons-material/ExpandLess';
import type { StrategyCard as StrategyCardType } from '@/shared/types/strategy';

interface StrategyCardProps {
  strategy: StrategyCardType;
  onClick?: (strategy: StrategyCardType) => void;
}

/** Priority color mapping */
function getPriorityColor(priority: string) {
  switch (priority) {
    case 'P0':
      return { bg: '#FEE2E2', color: '#DC2626', label: 'P0 紧急' };
    case 'P1':
      return { bg: '#FEF3C7', color: '#D97706', label: 'P1 重要' };
    case 'P2':
      return { bg: '#DBEAFE', color: '#2563EB', label: 'P2 常规' };
    default:
      return { bg: '#F3F4F6', color: '#6B7280', label: priority };
  }
}

/** Status chip mapping */
function getStatusChip(status: string) {
  switch (status) {
    case 'active':
      return { label: '执行中', color: 'success' as const };
    case 'draft':
      return { label: '草稿', color: 'default' as const };
    case 'archived':
      return { label: '已归档', color: 'default' as const };
    default:
      return { label: status, color: 'default' as const };
  }
}

/** Review status chip */
function getReviewChip(status: string) {
  switch (status) {
    case 'confirmed':
      return { label: '已确认', color: 'success' as const };
    case 'pending':
      return { label: '待审核', color: 'warning' as const };
    case 'rejected':
      return { label: '已驳回', color: 'error' as const };
    default:
      return { label: status, color: 'default' as const };
  }
}

/** Platform icon */
function getPlatformIcon(platform: string): string {
  return platform === 'xhs' ? '📕' : '🎵';
}

const StrategyCard: React.FC<StrategyCardProps> = ({ strategy, onClick }) => {
  const [expanded, setExpanded] = useState(false);
  const priorityInfo = getPriorityColor(strategy.priority);
  const statusInfo = getStatusChip(strategy.status);
  const reviewInfo = getReviewChip(strategy.reviewStatus);

  const handleClick = () => {
    onClick?.(strategy);
  };

  const handleExpandClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    setExpanded(!expanded);
  };

  return (
    <Card
      sx={{
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        transition: 'box-shadow 0.2s',
        '&:hover': { boxShadow: 4 },
        border: strategy.reviewStatus === 'pending' ? '1.5px solid' : '1px solid',
        borderColor:
          strategy.reviewStatus === 'pending' ? 'warning.main' : 'divider',
      }}
    >
      <CardActionArea onClick={handleClick} sx={{ flexGrow: 1 }}>
        <CardContent sx={{ pb: 1 }}>
          {/* Top row: priority + review status + platform */}
          <Box
            sx={{
              display: 'flex',
              alignItems: 'center',
              gap: 0.75,
              mb: 1,
              flexWrap: 'wrap',
            }}
          >
            <Chip
              label={priorityInfo.label}
              size="small"
              sx={{
                bgcolor: priorityInfo.bg,
                color: priorityInfo.color,
                fontWeight: 700,
                fontSize: 11,
              }}
            />
            <Chip
              label={statusInfo.label}
              size="small"
              color={statusInfo.color}
              variant="outlined"
              sx={{ fontSize: 11 }}
            />
            <Chip
              label={reviewInfo.label}
              size="small"
              color={reviewInfo.color}
              sx={{ fontSize: 11, ml: 'auto' }}
            />
            <Typography variant="body2" sx={{ fontSize: 18 }}>
              {getPlatformIcon(strategy.platform)}
            </Typography>
          </Box>

          {/* Title */}
          <Typography variant="subtitle2" fontWeight={600} gutterBottom>
            {strategy.title}
          </Typography>

          {/* Subtitle */}
          {strategy.subtitle && (
            <Typography
              variant="body2"
              color="text.secondary"
              sx={{ mb: 1, display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden' }}
            >
              {strategy.subtitle}
            </Typography>
          )}

          {/* Evidence preview (first 3) */}
          {strategy.evidence && strategy.evidence.length > 0 && (
            <Box sx={{ mb: 1 }}>
              <Typography variant="caption" color="text.disabled" sx={{ mb: 0.5, display: 'block' }}>
                评论证据 ({strategy.evidence.length}条)
              </Typography>
              {strategy.evidence.slice(0, 3).map((ev, idx) => (
                <Typography
                  key={idx}
                  variant="caption"
                  color="text.secondary"
                  sx={{
                    display: 'block',
                    fontStyle: 'italic',
                    pl: 1,
                    borderLeft: '2px solid',
                    borderColor: 'divider',
                    mb: 0.25,
                  }}
                >
                  "{ev.length > 80 ? ev.substring(0, 80) + '...' : ev}"
                </Typography>
              ))}
              {strategy.evidence.length > 3 && (
                <Box sx={{ display: 'flex', alignItems: 'center', mt: 0.25 }}>
                  <Typography variant="caption" color="primary.main" sx={{ cursor: 'pointer' }}>
                    +{strategy.evidence.length - 3} 条更多
                  </Typography>
                </Box>
              )}
            </Box>
          )}

          {/* KPI tags */}
          {strategy.expectedKPIs && strategy.expectedKPIs.length > 0 && (
            <Box sx={{ display: 'flex', gap: 0.5, flexWrap: 'wrap', mb: 0.5 }}>
              {strategy.expectedKPIs.map((kpi, idx) => (
                <Chip
                  key={idx}
                  label={kpi}
                  size="small"
                  variant="outlined"
                  color="primary"
                  sx={{ fontSize: 10, height: 20 }}
                />
              ))}
            </Box>
          )}
        </CardContent>
      </CardActionArea>
    </Card>
  );
};

export default StrategyCard;
