/**
 * StrategyPage — Strategy card list page with platform tabs and review status filters.
 *
 * Features:
 * - MUI Tabs: 小红书策略 / 抖音策略
 * - Filters: 全部 / 待审核 / 已确认 / 执行中
 * - Card grid with priority badges, status, evidence preview, KPI tags
 * - Click card → navigate to StrategyDetailPage
 */
import React, { useEffect, useState, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Box,
  Tabs,
  Tab,
  Typography,
  Grid,
  Chip,
  Stack,
  CircularProgress,
  Alert,
  Button,
} from '@mui/material';
import FilterListIcon from '@mui/icons-material/FilterList';
import { useBrandStore } from '@/shared/stores/brandStore';
import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '@/shared/db/db';
import type { StrategyCard as StrategyCardType } from '@/shared/types/strategy';
import StrategyCard from './StrategyCard';

type ReviewFilter = 'all' | 'pending' | 'confirmed' | 'active';

const StrategyPage: React.FC = () => {
  const { platform } = useParams<{ platform: string }>();
  const navigate = useNavigate();
  const currentBrandId = useBrandStore((s) => s.currentBrandId);

  const [tabPlatform, setTabPlatform] = useState<'xhs' | 'dy'>(
    platform === 'dy' ? 'dy' : 'xhs',
  );
  const [reviewFilter, setReviewFilter] = useState<ReviewFilter>('all');

  // Sync tab from URL on mount
  useEffect(() => {
    if (platform === 'dy' || platform === 'xhs') {
      setTabPlatform(platform);
    }
  }, [platform]);

  // Live query from DexieDB
  const allCards = useLiveQuery(
    () =>
      currentBrandId
        ? db.strategyCards.where({ brandId: currentBrandId }).toArray()
        : Promise.resolve([] as StrategyCardType[]),
    [currentBrandId],
  );

  const cards = useMemo(() => {
    if (!allCards) return [];
    let filtered = allCards.filter((c) => c.platform === tabPlatform);

    if (reviewFilter === 'pending') {
      filtered = filtered.filter((c) => c.reviewStatus === 'pending');
    } else if (reviewFilter === 'confirmed') {
      filtered = filtered.filter((c) => c.reviewStatus === 'confirmed');
    } else if (reviewFilter === 'active') {
      filtered = filtered.filter((c) => c.status === 'active');
    }

    // Sort by priority (P0 first) then by title
    const priorityOrder: Record<string, number> = { P0: 0, P1: 1, P2: 2 };
    return filtered.sort(
      (a, b) => (priorityOrder[a.priority] ?? 3) - (priorityOrder[b.priority] ?? 3),
    );
  }, [allCards, tabPlatform, reviewFilter]);

  const handleTabChange = (_: React.SyntheticEvent, newValue: 'xhs' | 'dy') => {
    setTabPlatform(newValue);
    navigate(`/strategy/${newValue}`, { replace: true });
  };

  const handleCardClick = (strategy: StrategyCardType) => {
    navigate(`/strategy/${strategy.platform}/detail/${strategy.id}`);
  };

  const filterChips: { value: ReviewFilter; label: string }[] = [
    { value: 'all', label: '全部' },
    { value: 'pending', label: '待审核' },
    { value: 'confirmed', label: '已确认' },
    { value: 'active', label: '执行中' },
  ];

  if (!currentBrandId) {
    return (
      <Box sx={{ p: 4, textAlign: 'center' }}>
        <Alert severity="info">请先在顶部选择一个品牌</Alert>
      </Box>
    );
  }

  return (
    <Box sx={{ p: 3, height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* Header */}
      <Box sx={{ mb: 2 }}>
        <Typography variant="h5" fontWeight={700} gutterBottom>
          策略卡
        </Typography>
        <Typography variant="body2" color="text.secondary">
          AI 生成的投放策略建议，按平台分组管理
        </Typography>
      </Box>

      {/* Platform Tabs */}
      <Tabs
        value={tabPlatform}
        onChange={handleTabChange}
        sx={{ mb: 2, borderBottom: 1, borderColor: 'divider' }}
      >
        <Tab label="📕 小红书策略" value="xhs" />
        <Tab label="🎵 抖音策略" value="dy" />
      </Tabs>

      {/* Filter chips */}
      <Stack direction="row" spacing={1} sx={{ mb: 3 }} alignItems="center">
        <FilterListIcon fontSize="small" color="action" />
        {filterChips.map((f) => (
          <Chip
            key={f.value}
            label={f.label}
            size="small"
            variant={reviewFilter === f.value ? 'filled' : 'outlined'}
            color={reviewFilter === f.value ? 'primary' : 'default'}
            onClick={() => setReviewFilter(f.value)}
            sx={{ cursor: 'pointer' }}
          />
        ))}
        <Box sx={{ flexGrow: 1 }} />
        <Typography variant="body2" color="text.secondary">
          共 {cards.length} 条策略
        </Typography>
      </Stack>

      {/* Card grid */}
      {allCards === undefined ? (
        <Box sx={{ display: 'flex', justifyContent: 'center', py: 8 }}>
          <CircularProgress />
        </Box>
      ) : cards.length === 0 ? (
        <Box
          sx={{
            textAlign: 'center',
            py: 8,
            flexGrow: 1,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          <Typography variant="h6" color="text.secondary" gutterBottom>
            暂无策略卡
          </Typography>
          <Typography variant="body2" color="text.disabled">
            {allCards.filter((c) => c.platform === tabPlatform).length === 0
              ? `尚未生成${tabPlatform === 'xhs' ? '小红书' : '抖音'}策略`
              : '当前筛选条件下无结果'}
          </Typography>
          <Button
            variant="outlined"
            size="small"
            sx={{ mt: 2 }}
            onClick={() => navigate('/ai-workbench')}
          >
            前往 AI 工作台生成策略
          </Button>
        </Box>
      ) : (
        <Grid container spacing={2}>
          {cards.map((card) => (
            <Grid item xs={12} sm={6} md={4} lg={3} key={card.id}>
              <StrategyCard strategy={card} onClick={handleCardClick} />
            </Grid>
          ))}
        </Grid>
      )}
    </Box>
  );
};

export default StrategyPage;
